inline bool logo_cell(int gx, int gy) {
    if (gx < 0 || gy < 0 || gx >= LOGO_W || gy >= LOGO_H) return false;
    return (LOGO_BITS[gy][gx >> 5] >> (gx & 31)) & 1u;
}

